import type { Suit as SuitType } from '../../engine/index.js';
import { Suit } from './Suit.js';

// Minimal-but-distinctive court-card decoration. We don't ship pixel-art
// kings/queens (bundle cost). Instead, a stylised geometric crest with a
// "JQK" monogram + the suit pip mirrored, top-and-bottom. Reads cleanly at
// every viewport including 360px wide.

interface CourtFaceProps {
  rank: 11 | 12 | 13;
  suit: SuitType;
}

const MONOGRAM: Record<11 | 12 | 13, string> = { 11: 'J', 12: 'Q', 13: 'K' };

export function CourtFace({ rank, suit }: CourtFaceProps) {
  return (
    <div className="ms-card-court" aria-hidden>
      <svg viewBox="0 0 100 140" preserveAspectRatio="xMidYMid meet" className="ms-card-court-svg">
        {/* Crest frame */}
        <rect
          x="14"
          y="20"
          width="72"
          height="100"
          rx="6"
          fill="none"
          stroke="currentColor"
          strokeOpacity="0.35"
          strokeWidth="1.5"
        />
        {/* Diagonal crosshatch lines for ornament */}
        <path
          d="M14 35 L 86 105 M 86 35 L 14 105"
          stroke="currentColor"
          strokeOpacity="0.10"
          strokeWidth="1"
        />
        {/* Top suit pip */}
        <g transform="translate(35, 30) scale(1.3)">
          <foreignObject x="0" y="0" width="24" height="24">
            <Suit suit={suit} />
          </foreignObject>
        </g>
        {/* Bottom suit pip (rotated 180°) */}
        <g transform="translate(65, 110) scale(-1.3, -1.3)">
          <foreignObject x="0" y="0" width="24" height="24">
            <Suit suit={suit} />
          </foreignObject>
        </g>
        {/* Center monogram */}
        <text
          x="50"
          y="80"
          textAnchor="middle"
          dominantBaseline="middle"
          fontSize="44"
          fontWeight="700"
          fontFamily="var(--mark-font, system-ui)"
          fill="currentColor"
        >
          {MONOGRAM[rank]}
        </text>
      </svg>
    </div>
  );
}
